using Microsoft.AspNetCore.Mvc;\nusing System.Collections.Generic;\n\nnamespace PractitionerSearchService.Controllers\n{\n    [ApiController]\n    [Route("api/[controller]")]\n    public class PractitionerSearchController : ControllerBase\n    {\n        // GET: api/practitionersearch\n        [HttpGet]\n        public ActionResult<IEnumerable<string>> GetPractitioners([FromQuery] string name)\n        {\n            // Ideally, you'd query your database using the provided name and return results.\n            // Here, we will return a static list for demonstration purposes.\n            var practitioners = new List<string>\n            {\n                "Practitioner 1: " + name,\n                "Practitioner 2: " + name\n            };\n            return Ok(practitioners);\n        }\n    }\n}